// Flatten all files from all folders
const driveFiles = $('Fetch Drive Files').first().json;
const processedReceipts = $('Fetch Processed Receipts').first().json.receipts || [];
const processedIds = new Set(processedReceipts.map(r => r.drive_file_id));

const IMAGE_TYPES = ['image/jpeg','image/png','image/webp','image/tiff','application/pdf'];

function flattenFiles(items, folderName = '') {
  const files = [];
  for (const item of items) {
    if (item.mimeType === 'application/vnd.google-apps.folder') {
      files.push(...flattenFiles(item.children || [], item.name));
    } else if (IMAGE_TYPES.includes(item.mimeType) && !processedIds.has(item.id)) {
      files.push({ ...item, folderName });
    }
  }
  return files;
}

const unprocessed = flattenFiles(Array.isArray(driveFiles) ? driveFiles : []);
return unprocessed.map(f => ({ json: f }));

const fileData = $('Filter Unprocessed Files').item.json;
const ocrData = $('OCR with GPT-4o Vision').item.json;

// Clean and validate the OCR output
let parsed = ocrData;
if (typeof ocrData === 'string') {
  try {
    parsed = JSON.parse(ocrData.replace(/```json|```/g, '').trim());
  } catch(e) {
    parsed = { status: 'failed', ocr_raw_text: ocrData };
  }
}

return [{
  json: {
    ...parsed,
    drive_file_id: fileData.id,
    drive_file_name: fileData.name,
    drive_folder_id: fileData.parents ? fileData.parents[0] : '',
    drive_folder_name: fileData.folderName || '',
  }
}];
